public int leerEnteroTeclado() {
    Scanner lector = new Scanner(System.in);
    boolean leido = false;
    int enteroLeido = 0;
    while (!leido) {
        if (lector.hasNextInt()) {
            enteroLeido = lector.nextInt();
            leido = true;
        } else {
            System.out.println("Esto no es un entero.");
            lector.next();
        }
        lector.nextLine();
    }
    return enteroLeido;
}

public double media(int[] array) {
    // Parám. entrada: el array de enteros
    // Parám. salida: la media (double)
    double acumulador = 0;
    for (int i = 0; i < array.length; i++) {
        acumulador = acumulador + array[i];
    }
    return acumulador / array.length;
}

Para generar un numero aleatorio entre 0 y 100 con la clase Random:
